  1→"use client";
  2→
  3→import { useState, useCallback } from "react";
  4→import { Plus, Loader2, AlertCircle } from "lucide-react";
  5→import { Button } from "@/components/ui/button";
  6→import { Input } from "@/components/ui/input";
  7→import { Textarea } from "@/components/ui/textarea";
  8→import {
  9→  Select,
 10→  SelectContent,
 11→  SelectItem,
 12→  SelectTrigger,
 13→  SelectValue,
 14→} from "@/components/ui/select";
 15→import {
 16→  Dialog,
 17→  DialogContent,
 18→  DialogHeader,
 19→  DialogTitle,
 20→  DialogFooter,
 21→  DialogTrigger,
 22→} from "@/components/ui/dialog";
 23→import { createInteraction } from "@/lib/api/interactions";
 24→import { ApiClientError } from "@/lib/api/shared";
 25→
 26→const INTERACTION_TYPES = [
 27→  { value: "call", label: "Call" },
 28→  { value: "meeting", label: "Meeting" },
 29→  { value: "email", label: "Email" },
 30→  { value: "note", label: "Note" },
 31→  { value: "task", label: "Task" },
 32→] as const;
 33→
 34→const DIRECTIONS = [
 35→  { value: "inbound", label: "Inbound" },
 36→  { value: "outbound", label: "Outbound" },
 37→] as const;
 38→
 39→const DIRECTION_TYPES = new Set(["call", "meeting", "email"]);
 40→
 41→interface InteractionFormProps {
 42→  contactId: string;
 43→  authorId: string;
 44→  onSuccess?: () => void;
 45→}
 46→
 47→export function InteractionForm({
 48→  contactId,
 49→  authorId,
 50→  onSuccess,
 51→}: InteractionFormProps) {
 52→  const [open, setOpen] = useState(false);
 53→  const [submitting, setSubmitting] = useState(false);
 54→  const [error, setError] = useState<string | null>(null);
 55→
 56→  const [type, setType] = useState<string>("");
 57→  const [direction, setDirection] = useState<string>("");
 58→  const [subject, setSubject] = useState("");
 59→  const [content, setContent] = useState("");
 60→  const [scheduledAt, setScheduledAt] = useState("");
 61→  const [completedAt, setCompletedAt] = useState("");
 62→
 63→  const resetForm = useCallback(() => {
 64→    setType("");
 65→    setDirection("");
 66→    setSubject("");
 67→    setContent("");
 68→    setScheduledAt("");
 69→    setCompletedAt("");
 70→    setError(null);
 71→  }, []);
 72→
 73→  const handleTypeChange = useCallback((value: string | null) => {
 74→    setType(value ?? "");
 75→  }, []);
 76→
 77→  const handleDirectionChange = useCallback((value: string | null) => {
 78→    setDirection(value ?? "");
 79→  }, []);
 80→
 81→  const handleOpenChange = useCallback(
 82→    (nextOpen: boolean) => {
 83→      setOpen(nextOpen);
 84→      if (!nextOpen) {
 85→        resetForm();
 86→      }
 87→    },
 88→    [resetForm]
 89→  );
 90→
 91→  const handleSubmit = useCallback(
 92→    async (e: React.FormEvent) => {
 93→      e.preventDefault();
 94→      setSubmitting(true);
 95→      setError(null);
 96→
 97→      try {
 98→        await createInteraction({
 99→          contactId,
100→          type,
101→          authorId,
102→          direction: DIRECTION_TYPES.has(type) ? direction || null : null,
103→          subject: subject || null,
104→          content: content || null,
105→          scheduledAt: scheduledAt || null,
106→          completedAt: completedAt || null,
107→        });
108→        setOpen(false);
109→        resetForm();
110→        onSuccess?.();
111→      } catch (err) {
112→        const message =
113→          err instanceof ApiClientError ? err.message : "Failed to create interaction";
114→        console.error("InteractionForm submit error:", err);
115→        setError(message);
116→      } finally {
117→        setSubmitting(false);
118→      }
119→    },
120→    [contactId, type, authorId, direction, subject, content, scheduledAt, completedAt, resetForm, onSuccess]
121→  );
122→
123→  return (
124→    <Dialog open={open} onOpenChange={handleOpenChange}>
125→      <DialogTrigger
126→        render={<Button variant="outline" size="sm" />}
127→      >
128→        <Plus className="size-4" />
129→        Add Interaction
130→      </DialogTrigger>
131→      <DialogContent className="sm:max-w-md">
132→        <DialogHeader>
133→          <DialogTitle>Add Interaction</DialogTitle>
134→        </DialogHeader>
135→        <form onSubmit={handleSubmit} className="flex flex-col gap-4">
136→          <div className="flex flex-col gap-1.5">
137→            <label className="text-xs font-medium text-muted-foreground">
138→              Type
139→            </label>
140→            <Select value={type} onValueChange={handleTypeChange}>
141→              <SelectTrigger className="w-full">
142→                <SelectValue placeholder="Select type" />
143→              </SelectTrigger>
144→              <SelectContent>
145→                {INTERACTION_TYPES.map((t) => (
146→                  <SelectItem key={t.value} value={t.value}>
147→                    {t.label}
148→                  </SelectItem>
149→                ))}
150→              </SelectContent>
151→            </Select>
152→          </div>
153→
154→          {DIRECTION_TYPES.has(type) && (
155→            <div className="flex flex-col gap-1.5">
156→              <label className="text-xs font-medium text-muted-foreground">
157→                Direction
158→              </label>
159→              <Select value={direction} onValueChange={handleDirectionChange}>
160→                <SelectTrigger className="w-full">
161→                  <SelectValue placeholder="Select direction" />
162→                </SelectTrigger>
163→                <SelectContent>
164→                  {DIRECTIONS.map((d) => (
165→                    <SelectItem key={d.value} value={d.value}>
166→                      {d.label}
167→                    </SelectItem>
168→                  ))}
169→                </SelectContent>
170→              </Select>
171→            </div>
172→          )}
173→
174→          <div className="flex flex-col gap-1.5">
175→            <label className="text-xs font-medium text-muted-foreground">
176→              Subject
177→            </label>
178→            <Input
179→              value={subject}
180→              onChange={(e) => setSubject(e.target.value)}
181→              placeholder="Interaction subject"
182→            />
183→          </div>
184→
185→          <div className="flex flex-col gap-1.5">
186→            <label className="text-xs font-medium text-muted-foreground">
187→              Content
188→            </label>
189→            <Textarea
190→              value={content}
191→              onChange={(e) => setContent(e.target.value)}
192→              placeholder="What happened?"
193→              rows={4}
194→            />
195→          </div>
196→
197→          <div className="grid grid-cols-2 gap-3">
198→            <div className="flex flex-col gap-1.5">
199→              <label className="text-xs font-medium text-muted-foreground">
200→                Scheduled
201→              </label>
202→              <Input
203→                type="datetime-local"
204→                value={scheduledAt}
205→                onChange={(e) => setScheduledAt(e.target.value)}
206→              />
207→            </div>
208→            <div className="flex flex-col gap-1.5">
209→              <label className="text-xs font-medium text-muted-foreground">
210→                Completed
211→              </label>
212→              <Input
213→                type="datetime-local"
214→                value={completedAt}
215→                onChange={(e) => setCompletedAt(e.target.value)}
216→              />
217→            </div>
218→          </div>
219→
220→          {error && (
221→            <div className="flex items-center gap-2 rounded-md bg-destructive/10 px-3 py-2 text-sm text-destructive">
222→              <AlertCircle className="size-4 shrink-0" />
223→              {error}
224→            </div>
225→          )}
226→
227→          <DialogFooter>
228→            <Button type="submit" disabled={submitting}>
229→              {submitting && <Loader2 className="mr-1 size-4 animate-spin" />}
230→              Save
231→            </Button>
232→          </DialogFooter>
233→        </form>
234→      </DialogContent>
235→    </Dialog>
236→  );
237→}
